    /** Iterator for Tensor. */
    @NoOffset public static class Iterator extends Pointer {
        static { Loader.load(); }
        /** Pointer cast constructor. Invokes {@link Pointer#Pointer(Pointer)}. */
        public Iterator(Pointer p) { super(p); }
      // Typically Tensor&, but a tensor slice
                                       // creates a new Tensor object with
                                       // shared memory.

        // Iterator must be constructible, copy-constructible, copy-assignable,
        // destructible and swappable.
        public Iterator(@Cast("Pointer") Tensor tensor, @Cast("int64_t") long index) { super((Pointer)null); allocate(tensor, index); }
        private native void allocate(@Cast("Pointer") Tensor tensor, @Cast("int64_t") long index);
        public Iterator(@Const @ByRef Iterator arg0) { super((Pointer)null); allocate(arg0); }
        private native void allocate(@Const @ByRef Iterator arg0);
        public native @ByVal @Cast("Pointer*") @Name("operator *") Tensor multiply();
        public native @Cast("Pointer") @Name("operator ->") Tensor access();
        public native @ByRef @Name("operator ++") Iterator increment();
        public native @ByVal @Name("operator ++") Iterator increment(int arg0);
        public native @Cast("bool") @Name("operator ==") boolean equals(@Const @ByRef Iterator other);
        public native @Cast("bool") @Name("operator !=") boolean notEquals(@Const @ByRef Iterator other);
    }

